// Get info about all windows and their tabs
const { windows } = chrome;
// We can't directly list tabs from here, but we can use the extension API
// Let's just return the current tab info
const tabs = await new Promise((resolve) => {
  chrome.tabs.query({}, (tabs) => resolve(tabs));
});
return tabs.map(t => ({ id: t.id, url: t.url, title: t.title }));
